# --- Constants & HTML Templates ---
EMBEDDED_HTML_INDEX = ""
EMBEDDED_HTML_RED = ""

def log_to_bot(msg):
    try:
        if "--udp" in sys.argv:
            port = int(sys.argv[sys.argv.index("--udp") + 1])
            import socket
            sock = socket.socket(socket.AF_INET, socket.SOCK_DGRAM)
            sock.sendto(msg.encode("utf-8"), ("127.0.0.1", port))
            sock.close()
    except Exception:
        pass

class NullWriter:
    def write(self, text): pass
    def flush(self): pass

if sys.stdout is None:
    sys.stdout = NullWriter()
if sys.stderr is None:
    sys.stderr = NullWriter()

if getattr(sys, 'frozen', False):
    BASE_DIR = getattr(sys, '_MEIPASS', os.path.dirname(os.path.abspath(sys.executable)))
    APP_DIR = os.path.dirname(os.path.abspath(sys.executable))
else:
    BASE_DIR = os.path.dirname(os.path.abspath(__file__))
    APP_DIR = BASE_DIR

DUMP_DIR = os.path.join(BASE_DIR, "okno", "site_dump")
if not os.path.exists(DUMP_DIR): DUMP_DIR = os.path.join(BASE_DIR, "site_dump")

ICON_PATH_TABL = os.path.join(BASE_DIR, "okno", "steam.ico")
ICON_PATH_ROOT = os.path.join(BASE_DIR, "steam.ico")
ICON_PATH_APP = os.path.join(APP_DIR, "steam.ico")
ICON_PATH = next((p for p in [ICON_PATH_TABL, ICON_PATH_ROOT, ICON_PATH_APP] if os.path.exists(p)), ICON_PATH_TABL)

_html_src_app = os.path.join(APP_DIR, "steamcommunity.com", "linkfilter", "path_index.html") 
_html_src_base = os.path.join(DUMP_DIR, "steamcommunity.com", "linkfilter", "path_index.html")
HTML_SRC = _html_src_app if os.path.exists(_html_src_app) else _html_src_base

def get_html_content(red=False):
    path = HTML_SRC if not red else HTML_SRC.replace(".html", "_red.html")
    if os.path.exists(path):
        with open(path, "r", encoding="utf-8") as f: return f.read()
    try:
        b64 = EMBEDDED_HTML_INDEX if not red else EMBEDDED_HTML_RED
        return base64.b64decode(b64).decode("utf-8")
    except: return "<html><body>Error</body></html>"

AGENT_NAME_FILE = os.path.join(APP_DIR, "tablichka", "agent_name.txt")

def _get_vac_lang() -> str:
    lang_file = os.path.join(APP_DIR, "tablichka", "vac_lang.txt")
    if os.path.exists(lang_file):
        try:
            with open(lang_file, "r") as f:
                l = f.read().strip().lower()
                if l in ("en", "cn"): return l
        except: pass
    return "en"

def _apply_localization(html: str, lang: str) -> str:
    if not (lang or "").lower().startswith("en"): return html
    html = html.replace("<h1>请注意：</h1>", "<h1>Attention:</h1>", 1)
    html = html.replace("<h2>账户访问受限。</h2>", "<h2>Account access restricted.</h2>", 1)
    return html

CDN_HOST = "steamcommunity.com" 
CDN_DIR = os.path.join(DUMP_DIR, CDN_HOST)  

RED_CSS_OVERRIDE = """<style id="color-override">
.friendlyInterstital .warningSign {
    background: linear-gradient(to bottom, #c0392b 5%, #922b21 95%) !important;
}
.warningExplanation p, .warningExplanation h2, .warningPanel p { color: #ffffff !important; }
</style>"""

def patch_html() -> str:
    html = get_html_content(red=False)
    html = _apply_localization(html, _get_vac_lang())
    if RED_CSS_OVERRIDE not in html:
        html = html.replace("</head>", RED_CSS_OVERRIDE + "\n</head>")
    return html

class SteamNoticeApi:
    def __init__(self): self._win = None
    def close_window(self):
        if self._win: self._win.destroy()
    def proceed_with_cookies(self): pass

def main():
    api = SteamNoticeApi()
    _shell32 = getattr(getattr(ctypes, 'windll', None), 'shell32', None)
    if _shell32: _shell32.SetCurrentProcessExplicitAppUserModelID("Valve.Steam.Notice") 
    patched_html = patch_html()
    window = webview.create_window(title="Steam", html=patched_html, width=1024, height=768, js_api=api)
    api._win = window
    webview.start(debug=False)

if __name__ == "__main__": main()
